patch:
--- a/comparator_64bit.v
+++ b/comparator_64bit.v
@@ -1,8 +1,8 @@
 module comparator_64bit(
   input [63:0] data_p, data_q,
   output reg equal, less_than
 );

-  always @(data_p)
+  always @(data_p or data_q)
     begin
       equal = (data_p == data_q);
       less_than = (data_p < data_q);

before_code:
module comparator_64bit(
  input [63:0] data_p, data_q,
  output reg equal, less_than
);

  always @(data_p)
    begin
      equal = (data_p == data_q);
      less_than = (data_p < data_q);
    end

endmodule

after_code:
module comparator_64bit(
  input [63:0] data_p, data_q,
  output reg equal, less_than
);

  always @(data_p or data_q)
    begin
      equal = (data_p == data_q);
      less_than = (data_p < data_q);
    end

endmodule
